        return poly(xs, x)

    lo, hi = -1.0, 1.0
    flo, fhi = f(lo), f(hi)

    while flo == 0:
        return lo
    while fhi == 0:
        return hi

    while flo * fhi > 0:
        lo *= 2
        hi *= 2
        flo, fhi = f(lo), f(hi)

