def minPath(grid, k):
    n = len(grid)
    pos = [None] * (n * n + 1)
    for i in range(n):
        for j in range(n):
            pos[grid[i][j]] = (i, j)

    if k == 1:
        return [1]

    dirs = ((1, 0), (-1, 0), (0, 1), (0, -1))

    def neighbors(v):
        i, j = pos[v]
        res = []
        for di, dj in dirs:
            ni, nj = i + di, j + dj
            if 0 <= ni < n and 0 <= nj < n:
                res.append(grid[ni][nj])
        return res

    vals = list(range(1, n * n + 1))
    cur = vals[:]
    ans = []

    for step in range(k):
        m = min(cur)
        ans.append(m)
        if step == k - 1:
            break
        nxt = []
        seen = set()
        for v in cur:
            if v == m:
                for u in neighbors(v):
                    if u not in seen:
                        seen.add(u)
                        nxt.append(u)
        cur = nxt

    return ans

