    current = []
    balance = 0

    for ch in paren_string:
        if ch == ' ':
            continue
        current.append(ch)
        if ch == '(':
            balance += 1
        elif ch == ')':
            balance -= 1
            if balance == 0:
                groups.append(''.join(current))
